function PartnerRegister({ goBack, type }) {
  const cfg = REGISTER_CONFIGS[type];
  const Icon = cfg.icon;
  const [step, setStep] = useState(1); // 1 personal, 2 details, 3 documents, 4 confirmed
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [city, setCity] = useState("Riyadh");
  const [district, setDistrict] = useState(SAUDI_CITIES["Riyadh"][0]);
  const [details, setDetails] = useState({});
  const [checkedDocs, setCheckedDocs] = useState({});
  const [referralCode, setReferralCode] = useState("");
  const [logoFile, setLogoFile] = useState(null);
  const [logoPreview, setLogoPreview] = useState(null);
  const [galleryFiles, setGalleryFiles] = useState([]); // { file, previewUrl }
  const logoInputRef = useRef(null);
  const galleryInputRef = useRef(null);
  const MAX_GALLERY = 20;
  const showsCompanyPhotos = type === "logistics_company" || type === "fleet_owner" || type === "food_partner";
  const showsCarPhotos = type === "rental_owner";
  const showsReferralCode = type === "food_partner" || type === "fleet_owner" || type === "logistics_company";
  const showsLocation = type === "food_partner";
  const [coords, setCoords] = useState(SAUDI_CITY_COORDS.Riyadh);
  const [address, setAddress] = useState("");
  const [locating, setLocating] = useState(false);
  const [locError, setLocError] = useState("");

  async function reverseGeocodeCoords(lat, lng) {
    try {
      const res = await hereFetch(`https://revgeocode.search.hereapi.com/v1/revgeocode?at=${lat},${lng}&lang=en-US`);
      const data = await res.json();
      return data?.items?.[0]?.address?.label || `${lat.toFixed(4)}, ${lng.toFixed(4)}`;
    } catch (e) { return `${lat.toFixed(4)}, ${lng.toFixed(4)}`; }
  }

  async function onPinMove(newCoords) {
    setCoords(newCoords);
    const label = await reverseGeocodeCoords(newCoords.lat, newCoords.lng);
    setAddress(label);
  }

  function useMyLocationForPartner() {
    detectLocation({
      onStart: () => { setLocating(true); setLocError(""); },
      onSuccess: ({ label, lat, lng }) => { setAddress(label); setCoords({ lat, lng }); setLocating(false); },
      onError: (msg) => { setLocating(false); setLocError(msg); },
    });
  }

  function handleLogoSelected(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setLogoFile(file);
    setLogoPreview(URL.createObjectURL(file));
    e.target.value = "";
  }
  function handleGallerySelected(e) {
    const files = Array.from(e.target.files || []);
    if (!files.length) return;
    const room = MAX_GALLERY - galleryFiles.length;
    const toAdd = files.slice(0, room).map((file) => ({ file, previewUrl: URL.createObjectURL(file) }));
    setGalleryFiles((prev) => [...prev, ...toAdd]);
    e.target.value = "";
  }
  function removeGalleryPhoto(idx) {
    setGalleryFiles((prev) => prev.filter((_, i) => i !== idx));
  }

  const step1Valid = name.trim() && phone.trim();
  const needsRealAuth = type === "food_partner" || type === "logistics_company" || type === "rental_owner" || type === "agent";
  const step2Valid = cfg.detailFields.filter((f) => !f.optional).every((f) => (details[f.key] || "").trim())
    && (!needsRealAuth || (/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()) && password.length >= 6));
  const step3Valid = cfg.documents.every((d) => checkedDocs[d]);
  const [submitting, setSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState("");

  function toggleDoc(d) {
    setCheckedDocs((c) => ({ ...c, [d]: !c[d] }));
  }

  // Looks up an agent by referral code so their id + commission rate can be
  // attached to the new restaurant/company/logistics company being created.
  // Silently ignored if the code is blank or doesn't match — referral is optional.
  async function resolveAgentFromCode() {
    const code = referralCode.trim();
    if (!code) return { agent_id: null, agent_commission_rate: null };
    const { data: agent } = await supabase.from("agents").select("id, default_commission_rate").eq("referral_code", code.toUpperCase()).maybeSingle();
    if (!agent) return { agent_id: null, agent_commission_rate: null };
    return { agent_id: agent.id, agent_commission_rate: agent.default_commission_rate };
  }

  async function submitApplication() {
    setSubmitting(true);
    setSubmitError("");
    try {
      const detailsText = cfg.detailFields.map((f) => `${f.label}: ${details[f.key]}`).join(" · ");
      // Kept for your records — every application still logs here regardless of type.
      const { error: appError } = await supabase.from("partner_applications").insert({
        type,
        full_name: name,
        phone,
        email: email || null,
        city,
        district,
        details: detailsText,
        status: "pending",
      });
      if (appError) throw appError;

      // Rentals, marketplace items, restaurants, and fleet companies publish live
      // immediately — no manual review needed to appear in lists. Driver and
      // logistics applications still need a real account (handled separately via
      // Login/Signup) so those stay as review-only applications above. Fleet
      // companies get a pending listing now, but still need Company Sign Up to
      // get a real login for the dashboard.
      if (type === "rental_owner") {
        if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim())) throw new Error("Please enter a valid email — this is how you'll log in to manage your car listing.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");
        let authUserId = null;
        const { data: { user: existingUser } } = await supabase.auth.getUser();
        if (existingUser) {
          authUserId = existingUser.id;
        } else {
          authUserId = await signUpOrLinkExisting(email.trim(), password, { role: "car_owner" });
          await supabase.rpc("claim_legacy_listings_bulk", { p_table: "rental_listings", p_phone_column: "owner_phone", p_phone: phone.trim() });
        }
        const galleryUrls = [];
        for (const g of galleryFiles) {
          const ext = g.file.name.split(".").pop() || "jpg";
          const fileName = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
          const { error: galErr } = await supabase.storage.from("company-photos").upload(fileName, g.file);
          if (galErr) continue;
          const { data: pub } = supabase.storage.from("company-photos").getPublicUrl(fileName);
          galleryUrls.push(pub.publicUrl);
        }
        const { error: listingError } = await supabase.from("rental_listings").insert({
          owner_name: name.trim(),
          owner_phone: phone.trim(),
          auth_user_id: authUserId,
          provider: `Private owner — ${name.trim()}`,
          model: details.vehicleModel || "Car for rent",
          price_per_day: parseFloat(details.dailyRate) || null,
          weekly_price: parseFloat(details.weeklyRate) || null,
          monthly_price: parseFloat(details.monthlyRate) || null,
          city,
          image_url: galleryUrls[0] || null,
          gallery_urls: galleryUrls,
          status: "active",
        });
        if (listingError) throw listingError;
      } else if (type === "seller") {
        const { error: listingError } = await supabase.from("marketplace_listings").insert({
          title: details.storeName || "New listing",
          category: details.category || "Other",
          location: city,
          seller_name: name,
          seller_phone: phone,
          status: "active",
        });
        if (listingError) throw listingError;
      } else if (type === "food_partner") {
        if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim())) throw new Error("Please enter a valid email — this is how you'll log in to manage your restaurant.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");
        const authUserId = await signUpOrLinkExisting(email.trim(), password, { role: "restaurant_owner" });
        const { data: claimedId } = await supabase.rpc("claim_legacy_business", { p_table: "restaurants", p_phone_column: "owner_phone", p_phone: phone.trim() });
        const { agent_id, agent_commission_rate } = await resolveAgentFromCode();

        let logoUrl = null;
        if (logoFile) {
          const ext = logoFile.name.split(".").pop() || "jpg";
          const fileName = `${Date.now()}-logo-${Math.random().toString(36).slice(2, 8)}.${ext}`;
          const { error: logoErr } = await supabase.storage.from("company-logos").upload(fileName, logoFile);
          if (!logoErr) {
            const { data: pub } = supabase.storage.from("company-logos").getPublicUrl(fileName);
            logoUrl = pub.publicUrl;
          }
        }
        const galleryUrls = [];
        for (const g of galleryFiles) {
          const ext = g.file.name.split(".").pop() || "jpg";
          const fileName = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
          const { error: galErr } = await supabase.storage.from("company-photos").upload(fileName, g.file);
          if (galErr) continue;
          const { data: pub } = supabase.storage.from("company-photos").getPublicUrl(fileName);
          galleryUrls.push(pub.publicUrl);
        }
        if (claimedId) {
          const { error: updErr } = await supabase.from("restaurants").update({
            name: details.restaurantName || name, cuisine: details.cuisine || "Restaurant", city,
            logo_url: logoUrl, gallery_urls: galleryUrls, email: email.trim(), status: "active",
            lat: coords.lat, lng: coords.lng, address: address || null,
            ...(agent_id ? { agent_id, agent_commission_rate } : {}),
          }).eq("id", claimedId);
          if (updErr) throw updErr;
        } else {
          const { error: listingError } = await supabase.from("restaurants").insert({
            name: details.restaurantName || name,
            cuisine: details.cuisine || "Restaurant",
            city,
            logo_url: logoUrl,
            gallery_urls: galleryUrls,
            owner_phone: phone.trim(),
            auth_user_id: authUserId,
            email: email.trim(),
            status: "active",
            lat: coords.lat,
            lng: coords.lng,
            address: address || null,
            agent_id,
            agent_commission_rate,
          });
          if (listingError) throw listingError;
        }
      } else if (type === "fleet_owner") {
        const { agent_id, agent_commission_rate } = await resolveAgentFromCode();
        let logoUrl = null;
        if (logoFile) {
          const ext = logoFile.name.split(".").pop() || "jpg";
          const fileName = `${Date.now()}-logo-${Math.random().toString(36).slice(2, 8)}.${ext}`;
          const { error: logoErr } = await supabase.storage.from("company-logos").upload(fileName, logoFile);
          if (!logoErr) {
            const { data: pub } = supabase.storage.from("company-logos").getPublicUrl(fileName);
            logoUrl = pub.publicUrl;
          }
        }
        const photoUrls = [];
        for (const g of galleryFiles) {
          const ext = g.file.name.split(".").pop() || "jpg";
          const fileName = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
          const { error: galErr } = await supabase.storage.from("company-photos").upload(fileName, g.file);
          if (galErr) continue;
          const { data: pub } = supabase.storage.from("company-photos").getPublicUrl(fileName);
          photoUrls.push(pub.publicUrl);
        }
        const { error: companyError } = await supabase.from("companies").insert({
          name: details.companyName || name,
          contact_name: name,
          mobile_number: phone,
          email: email || null,
          fleet_size: parseInt(details.fleetSize, 10) || 0,
          logo_url: logoUrl,
          photo_urls: photoUrls,
          status: "active",
          verified: true,
          agent_id,
          agent_commission_rate,
        });
        if (companyError) throw companyError;
      } else if (type === "logistics_company") {
        if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim())) throw new Error("Please enter a valid email — this is how you'll log in to manage your cargo company.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");
        const authUserId = await signUpOrLinkExisting(email.trim(), password, { role: "logistics_company_owner" });
        const { data: claimedId } = await supabase.rpc("claim_legacy_business", { p_table: "logistics_companies", p_phone_column: "owner_phone", p_phone: phone.trim() });
        const { agent_id: logisticsAgentId, agent_commission_rate: logisticsAgentRate } = await resolveAgentFromCode();

        let logoUrl = null;
        if (logoFile) {
          const ext = logoFile.name.split(".").pop() || "jpg";
          const fileName = `${Date.now()}-logo-${Math.random().toString(36).slice(2, 8)}.${ext}`;
          const { error: logoErr } = await supabase.storage.from("company-logos").upload(fileName, logoFile);
          if (!logoErr) {
            const { data: pub } = supabase.storage.from("company-logos").getPublicUrl(fileName);
            logoUrl = pub.publicUrl;
          }
        }
        const galleryUrls = [];
        for (const g of galleryFiles) {
          const ext = g.file.name.split(".").pop() || "jpg";
          const fileName = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
          const { error: galErr } = await supabase.storage.from("company-photos").upload(fileName, g.file);
          if (galErr) continue;
          const { data: pub } = supabase.storage.from("company-photos").getPublicUrl(fileName);
          galleryUrls.push(pub.publicUrl);
        }
        if (claimedId) {
          const { error: updErr } = await supabase.from("logistics_companies").update({
            company_name: details.companyName || name, owner_name: name, city,
            service_area: details.serviceArea || city, fleet_size: parseInt(details.fleetSize, 10) || 0,
            logo_url: logoUrl, gallery_urls: galleryUrls, email: email.trim(), status: "active",
            ...(logisticsAgentId ? { agent_id: logisticsAgentId, agent_commission_rate: logisticsAgentRate } : {}),
          }).eq("id", claimedId);
          if (updErr) throw updErr;
        } else {
          const { error: logisticsCoError } = await supabase.from("logistics_companies").insert({
            company_name: details.companyName || name,
            owner_name: name,
            owner_phone: phone.trim(),
            auth_user_id: authUserId,
            email: email.trim(),
            city,
            service_area: details.serviceArea || city,
            fleet_size: parseInt(details.fleetSize, 10) || 0,
            logo_url: logoUrl,
            gallery_urls: galleryUrls,
            status: "active",
            verified: false,
            agent_id: logisticsAgentId,
            agent_commission_rate: logisticsAgentRate,
          });
          if (logisticsCoError) throw logisticsCoError;
        }
      } else if (type === "agent") {
        if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim())) throw new Error("Please enter a valid email — this is how you'll log in to your agent dashboard.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");
        const authUserId = await signUpOrLinkExisting(email.trim(), password, { role: "agent" });
        const namePart = (name.trim().split(/\s+/)[0] || "AGENT").toUpperCase().replace(/[^A-Z]/g, "").slice(0, 6) || "AGENT";
        const code = `SAY-${namePart}${Math.floor(10000 + Math.random() * 90000)}`;
        const { error: agentError } = await supabase.from("agents").insert({
          full_name: name.trim(),
          phone: phone.trim(),
          email: email.trim(),
          city,
          referral_code: code,
          auth_user_id: authUserId,
        });
        if (agentError) throw agentError;
      }

      await supabase.from("notifications").insert({
        recipient_type: "admin",
        title: type === "agent" ? "New agent joined" : ["rental_owner", "seller", "food_partner", "fleet_owner", "logistics_company"].includes(type) ? "New listing published" : "New application received",
        body: type === "agent" ? `${name} joined as an agent and can now refer restaurants and companies.` : `${name} ${["rental_owner", "seller", "food_partner", "fleet_owner", "logistics_company"].includes(type) ? "published a listing as a" : "applied as a"} ${type.replace(/_/g, " ")}`,
      });
      setStep(4);
    } catch (e) {
      setSubmitError("Something went wrong submitting your application. Please try again.");
    } finally {
      setSubmitting(false);
    }
  }

  const STEPS = ["Personal", "Details", "Documents"];

  return (
    <div style={{ color: TEXT }}>
      <Header title={cfg.title} onBack={goBack} />

      {step <= 3 && (
        <>
          <div className="px-5 mb-5 flex items-center gap-3">
            <div className="w-11 h-11 rounded-xl flex items-center justify-center shrink-0" style={{ background: "rgba(217,166,83,0.14)" }}>
              <Icon size={20} color={GOLD} />
            </div>
            <p className="text-xs" style={{ color: MUTE }}>{cfg.intro}</p>
          </div>

          <div className="px-5 mb-6 flex items-center gap-2">
            {STEPS.map((s, i) => (
              <div key={s} className="flex-1 flex items-center gap-2">
                <div
                  className="w-full h-1.5 rounded-full"
                  style={{ background: i + 1 <= step ? GOLD : BORDER }}
                />
              </div>
            ))}
          </div>
        </>
      )}

      {step === 1 && (
        <div className="px-5">
          <p className="text-xs font-semibold mb-2" style={{ color: GREEN }}>PERSONAL INFORMATION</p>
          <div className="flex flex-col gap-3 mb-6">
            <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
              <User size={14} color={GOLD} />
              <input value={name} onChange={(e) => setName(e.target.value)} placeholder="Full name" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
            </div>
            <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
              <Phone size={14} color={GOLD} />
              <input value={phone} onChange={(e) => setPhone(e.target.value)} placeholder="Phone number (WhatsApp)" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
            </div>
            <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
              <Mail size={14} color={GOLD} />
              <input value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Email (optional)" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
            </div>
            <div className="rounded-xl px-4 py-2" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
              <div className="flex items-center gap-3 py-2.5" style={{ borderBottom: `1px solid ${BORDER}` }}>
                <MapPin size={14} color={GREEN} />
                <select value={city} onChange={(e) => { setCity(e.target.value); setDistrict(SAUDI_CITIES[e.target.value][0]); }} className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }}>
                  {SAUDI_CITY_LIST.map((c) => <option key={c} style={{ background: CARD }}>{c}</option>)}
                </select>
              </div>
              <div className="flex items-center gap-3 py-2.5">
                <MapPin size={14} color={GOLD} />
                <select value={district} onChange={(e) => setDistrict(e.target.value)} className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }}>
                  {SAUDI_CITIES[city].map((d) => <option key={d} style={{ background: CARD }}>{d}</option>)}
                </select>
              </div>
            </div>
          </div>
          <button onClick={() => step1Valid && setStep(2)} disabled={!step1Valid} className="w-full rounded-full py-3 text-sm font-semibold flex items-center justify-center gap-2" style={{ background: step1Valid ? GOLD : BORDER, color: step1Valid ? BG : "#5C736D" }}>
            Continue <ChevronRight size={16} />
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="px-5">
          <p className="text-xs font-semibold mb-2" style={{ color: GREEN }}>
            {type === "seller" || type === "food_partner" || type === "fleet_owner" ? "BUSINESS DETAILS" : "VEHICLE DETAILS"}
          </p>
          <div className="flex flex-col gap-3 mb-6">
            {cfg.detailFields.map((f) => (
              <div key={f.key} className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
                <ChevronRight size={14} color={GOLD} />
                <input
                  value={details[f.key] || ""}
                  onChange={(e) => setDetails((d) => ({ ...d, [f.key]: e.target.value }))}
                  placeholder={f.placeholder}
                  className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }}
                />
              </div>
            ))}
          </div>

          {showsLocation && (
            <div className="mb-6">
              <p className="text-xs font-semibold mb-2" style={{ color: GREEN }}>EXACT LOCATION</p>
              {address && <p className="text-[11px] mb-2 flex items-center gap-1.5" style={{ color: MUTE }}><MapPin size={12} color={GOLD} /> {address}</p>}
              <div className="flex items-center justify-between mb-2">
                <p className="text-[10px]" style={{ color: FAINT }}>Drag the pin to your exact location</p>
                <button onClick={useMyLocationForPartner} disabled={locating} className="flex items-center gap-1.5 text-[11px] font-semibold" style={{ color: GOLD }}>
                  <Navigation size={12} /> {locating ? "Detecting…" : "Use my current location"}
                </button>
              </div>
              {locError && <p className="text-[11px] mb-2" style={{ color: "#C0755B" }}>{locError}</p>}
              <div className="rounded-2xl overflow-hidden" style={{ border: `1px solid ${BORDER}` }}>
                <PinMapPicker coords={coords} onMove={onPinMove} height={170} />
              </div>
            </div>
          )}

          {showsReferralCode && (
            <div className="mb-6">
              <p className="text-xs font-semibold mb-2" style={{ color: GREEN }}>REFERRAL (OPTIONAL)</p>
              <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
                <Users2 size={14} color={GOLD} />
                <input
                  value={referralCode}
                  onChange={(e) => setReferralCode(e.target.value)}
                  placeholder="Agent referral code, if someone signed you up"
                  className="bg-transparent outline-none text-sm w-full uppercase"
                  style={{ color: TEXT }}
                />
              </div>
            </div>
          )}

          {(type === "food_partner" || type === "logistics_company" || type === "rental_owner" || type === "agent") && (
            <>
              <p className="text-xs font-semibold mb-2" style={{ color: GREEN }}>YOUR LOGIN</p>
              <div className="flex flex-col gap-3 mb-6">
                <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${GOLD}` }}>
                  <Mail size={14} color={GOLD} />
                  <input value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Email — used to log in" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
                </div>
                <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${GOLD}` }}>
                  <Key size={14} color={GOLD} />
                  <input value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Password (min 6 characters)" type="password" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
                </div>
                <p className="text-[10px] -mt-2" style={{ color: FAINT }}>This becomes your real login — only you, signed in, can ever edit or manage this listing.</p>
              </div>
            </>
          )}

          {showsCompanyPhotos && (
            <>
              <p className="text-xs font-semibold mb-2" style={{ color: GREEN }}>COMPANY LOGO</p>
              <div className="flex items-center gap-3 mb-6">
                <button onClick={() => logoInputRef.current?.click()} className="w-16 h-16 rounded-2xl overflow-hidden flex items-center justify-center shrink-0" style={{ background: CARD, border: `1px dashed ${BORDER}` }}>
                  {logoPreview ? <img src={logoPreview} alt="Logo" className="w-full h-full object-cover" /> : <ImageIcon size={18} color={FAINT} />}
                </button>
                <div>
                  <button onClick={() => logoInputRef.current?.click()} className="text-xs font-semibold" style={{ color: GOLD }}>{logoPreview ? "Change logo" : "Upload logo"}</button>
                  <p className="text-[10px] mt-0.5" style={{ color: FAINT }}>Square image works best</p>
                </div>
                <input ref={logoInputRef} type="file" accept="image/*" className="hidden" onChange={handleLogoSelected} />
              </div>

              <p className="text-xs font-semibold mb-2" style={{ color: GREEN }}>COMPANY PHOTOS ({galleryFiles.length}/{MAX_GALLERY})</p>
              <p className="text-[10px] mb-2.5" style={{ color: FAINT }}>Vehicles, warehouse, team — add as many as you like.</p>
              <div className="grid grid-cols-3 gap-2 mb-6">
                {galleryFiles.map((g, i) => (
                  <div key={i} className="relative aspect-square rounded-xl overflow-hidden" style={{ border: `1px solid ${BORDER}` }}>
                    <img src={g.previewUrl} alt="" className="w-full h-full object-cover" />
                    <button onClick={() => removeGalleryPhoto(i)} className="absolute top-1 right-1 w-5 h-5 rounded-full flex items-center justify-center" style={{ background: "rgba(7,14,31,0.75)" }}>
                      <X size={11} color="#fff" />
                    </button>
                  </div>
                ))}
                {galleryFiles.length < MAX_GALLERY && (
                  <button onClick={() => galleryInputRef.current?.click()} className="aspect-square rounded-xl flex flex-col items-center justify-center gap-1" style={{ background: CARD, border: `1px dashed ${BORDER}` }}>
                    <Plus size={16} color={FAINT} />
                    <span className="text-[9px]" style={{ color: FAINT }}>Add photos</span>
                  </button>
                )}
              </div>
              <input ref={galleryInputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleGallerySelected} />
            </>
          )}

          {showsCarPhotos && (
            <>
              <p className="text-xs font-semibold mb-2" style={{ color: GREEN }}>CAR PHOTOS ({galleryFiles.length}/{MAX_GALLERY})</p>
              <p className="text-[10px] mb-2.5" style={{ color: FAINT }}>Exterior, interior, mileage — the more photos, the more trust.</p>
              <div className="grid grid-cols-3 gap-2 mb-6">
                {galleryFiles.map((g, i) => (
                  <div key={i} className="relative aspect-square rounded-xl overflow-hidden" style={{ border: `1px solid ${BORDER}` }}>
                    <img src={g.previewUrl} alt="" className="w-full h-full object-cover" />
                    <button onClick={() => removeGalleryPhoto(i)} className="absolute top-1 right-1 w-5 h-5 rounded-full flex items-center justify-center" style={{ background: "rgba(7,14,31,0.75)" }}>
                      <X size={11} color="#fff" />
                    </button>
                    {i === 0 && <span className="absolute bottom-1 left-1 px-1.5 py-0.5 rounded-full text-[8px] font-semibold" style={{ background: GOLD, color: BG }}>Cover</span>}
                  </div>
                ))}
                {galleryFiles.length < MAX_GALLERY && (
                  <button onClick={() => galleryInputRef.current?.click()} className="aspect-square rounded-xl flex flex-col items-center justify-center gap-1" style={{ background: CARD, border: `1px dashed ${BORDER}` }}>
                    <Plus size={16} color={FAINT} />
                    <span className="text-[9px]" style={{ color: FAINT }}>Add photos</span>
                  </button>
                )}
              </div>
              <input ref={galleryInputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleGallerySelected} />
            </>
          )}

          <div className="flex gap-2">
            <button onClick={() => setStep(1)} className="flex-1 rounded-full py-3 text-sm font-semibold" style={{ background: BORDER, color: TEXT }}>Back</button>
            <button onClick={() => step2Valid && setStep(3)} disabled={!step2Valid} className="flex-1 rounded-full py-3 text-sm font-semibold flex items-center justify-center gap-2" style={{ background: step2Valid ? GOLD : BORDER, color: step2Valid ? BG : "#5C736D" }}>
              Continue <ChevronRight size={16} />
            </button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="px-5">
          <p className="text-xs font-semibold mb-2" style={{ color: GREEN }}>REQUIRED DOCUMENTS</p>
          <p className="text-[11px] mb-4" style={{ color: FAINT }}>Confirm you have these ready — you'll upload them after submitting, or send via WhatsApp.</p>
          <div className="flex flex-col gap-2 mb-6">
            {cfg.documents.map((d) => (
              <button key={d} onClick={() => toggleDoc(d)} className="w-full flex items-center gap-3 rounded-xl px-4 py-3 text-left" style={{ background: CARD, border: checkedDocs[d] ? `1px solid ${GOLD}` : `1px solid ${BORDER}` }}>
                <div className="w-5 h-5 rounded-md flex items-center justify-center shrink-0" style={{ background: checkedDocs[d] ? GOLD : "transparent", border: `1px solid ${checkedDocs[d] ? GOLD : BORDER}` }}>
                  {checkedDocs[d] && <Check size={13} color={BG} />}
                </div>
                <span className="text-sm">{d}</span>
              </button>
            ))}
          </div>
          {submitError && <p className="text-[12px] mb-2" style={{ color: "#C0755B" }}>{submitError}</p>}
          <div className="flex gap-2">
            <button onClick={() => setStep(2)} className="flex-1 rounded-full py-3 text-sm font-semibold" style={{ background: BORDER, color: TEXT }}>Back</button>
            <button onClick={submitApplication} disabled={!step3Valid || submitting} className="flex-1 rounded-full py-3 text-sm font-semibold flex items-center justify-center gap-2" style={{ background: step3Valid ? GOLD : BORDER, color: step3Valid ? BG : "#5C736D" }}>
              {submitting ? "Submitting…" : "Submit application"}
            </button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="px-5 mt-8 flex flex-col items-center text-center">
          <CheckCircle2 size={44} color={GREEN} />
          <h2 className="mt-4 text-lg font-semibold">Application submitted</h2>
          <p className="mt-1 text-sm" style={{ color: MUTE }}>
            Our team will review your application and contact you on WhatsApp within 2-3 business days.
          </p>
          <div className="mt-6 w-full rounded-2xl px-4 py-4 text-left" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <div className="flex justify-between text-sm py-1"><span style={{ color: FAINT }}>Applicant</span><span>{name}</span></div>
            <div className="flex justify-between text-sm py-1"><span style={{ color: FAINT }}>Phone</span><span>{phone}</span></div>
            <div className="flex justify-between text-sm py-1"><span style={{ color: FAINT }}>Location</span><span>{district}, {city}</span></div>
          </div>
          <button onClick={goBack} className="w-full mt-6 rounded-full py-3 text-sm font-semibold" style={{ background: BORDER, color: TEXT }}>Done</button>
        </div>
      )}

      <div className="h-10" />
    </div>
  );
}

