/* ---------- POST MARKETPLACE ITEM (with photos) ---------- */
const STORE_TYPES = ["Supermarket", "Electronics Store", "Fashion Boutique", "Furniture Store", "Auto Parts Shop", "Restaurant Supply", "Wholesale", "Retail Shop", "Other"];

function PostMarketplaceItem({ goBack, navigate, onLoggedIn }) {
  const [phase, setPhase] = useState("checking"); // "checking" | "no_session" | "form"
  const [store, setStore] = useState(null);

  const [title, setTitle] = useState("");
  const [price, setPrice] = useState("");
  const [category, setCategory] = useState("Electronics");
  const [description, setDescription] = useState("");
  const [location, setLocation] = useState("Riyadh");
  const [photos, setPhotos] = useState([]); // { file, previewUrl }
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState("");
  const fileInputRef = useRef(null);
  const MAX_PHOTOS = 6;

  useEffect(() => {
    async function checkSession() {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) { setPhase("no_session"); return; }
      const { data } = await supabase.from("stores").select("id, owner_name, owner_phone, store_name, store_type, logo_url, city, hours, description, status, lat, lng, address").eq("auth_user_id", user.id).maybeSingle();
      if (data) { setStore(data); setPhase("form"); if (onLoggedIn) onLoggedIn({ profile: data }); }
      else { setPhase("no_session"); }
    }
    checkSession();
  }, []);

  function handleFilesSelected(e) {
    const files = Array.from(e.target.files || []);
    if (!files.length) return;
    const room = MAX_PHOTOS - photos.length;
    const toAdd = files.slice(0, room).map((file) => ({ file, previewUrl: URL.createObjectURL(file) }));
    setPhotos((prev) => [...prev, ...toAdd]);
    e.target.value = "";
  }

  function removePhoto(idx) {
    setPhotos((prev) => prev.filter((_, i) => i !== idx));
  }

  async function submit() {
    setError("");
    if (!title.trim()) { setError("Please enter a title."); return; }
    if (!price || Number(price) <= 0) { setError("Please enter a valid price."); return; }
    setUploading(true);
    try {
      const uploadedUrls = [];
      for (const p of photos) {
        const ext = p.file.name.split(".").pop() || "jpg";
        const fileName = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
        const { error: upErr } = await supabase.storage.from("marketplace-images").upload(fileName, p.file);
        if (upErr) throw upErr;
        const { data: pub } = supabase.storage.from("marketplace-images").getPublicUrl(fileName);
        uploadedUrls.push(pub.publicUrl);
      }
      const { error: insertError } = await supabase.from("marketplace_listings").insert({
        title: title.trim(),
        price: Number(price),
        category,
        description: description.trim() || null,
        location,
        seller_phone: store.owner_phone,
        seller_name: store.store_name,
        store_id: store.id,
        image_url: uploadedUrls[0] || null,
        image_urls: uploadedUrls,
        status: "active",
      });
      if (insertError) throw insertError;
      photos.forEach((p) => URL.revokeObjectURL(p.previewUrl));
      navigate("market");
    } catch (e) {
      setError(e.message || "Something went wrong posting your listing.");
    } finally {
      setUploading(false);
    }
  }

  if (phase === "checking") {
    return (
      <div style={{ color: TEXT }}>
        <Header title="Post an item" onBack={goBack} />
        <div className="flex justify-center py-16"><SearchingAnimation /></div>
      </div>
    );
  }

  if (phase === "no_session") {
    return (
      <div style={{ color: TEXT }}>
        <Header title="Post an item" onBack={goBack} />
        <div className="px-5 flex flex-col items-center text-center py-8">
          <ShoppingBag size={32} color={GOLD} />
          <p className="text-sm font-semibold mt-3">Log in to your store to post items</p>
          <p className="text-xs mt-1" style={{ color: FAINT }}>Every listing is posted under your store account — this keeps it secure so only you can post to it.</p>
          <button onClick={() => navigate("store_login")} className="w-full mt-6 rounded-full py-3 text-sm font-semibold" style={{ background: GOLD, color: BG }}>Log in to my store</button>
          <button onClick={() => navigate("register_store")} className="w-full mt-2 rounded-full py-3 text-sm font-semibold" style={{ background: BORDER, color: TEXT }}>I don't have a store yet</button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ color: TEXT }}>
      <Header title="Post an item" onBack={goBack} />
      <div className="px-5">
        <div className="rounded-xl px-4 py-3 mb-4 flex items-center gap-3" style={{ background: "rgba(217,166,83,0.1)", border: `1px solid ${BORDER}` }}>
          <div className="w-9 h-9 rounded-lg overflow-hidden shrink-0 flex items-center justify-center" style={{ background: BORDER }}>
            {store.logo_url ? <img src={store.logo_url} alt="" className="w-full h-full object-cover" /> : <ShoppingBag size={15} color={FAINT} />}
          </div>
          <p className="text-xs flex-1" style={{ color: MUTE }}>Posting as <span style={{ color: GOLD, fontWeight: 600 }}>{store.store_name}</span></p>
          <button onClick={() => navigate("store_dashboard")} className="text-[10px] font-semibold shrink-0" style={{ color: GOLD }}>Dashboard →</button>
        </div>

        <p className="text-xs mb-2 font-semibold" style={{ color: MUTE }}>Photos ({photos.length}/{MAX_PHOTOS})</p>
        <div className="grid grid-cols-3 gap-2 mb-4">
          {photos.map((p, i) => (
            <div key={i} className="relative aspect-square rounded-xl overflow-hidden" style={{ border: `1px solid ${BORDER}` }}>
              <img src={p.previewUrl} alt="" className="w-full h-full object-cover" />
              <button onClick={() => removePhoto(i)} className="absolute top-1 right-1 w-5 h-5 rounded-full flex items-center justify-center" style={{ background: "rgba(7,14,31,0.75)" }}>
                <X size={11} color="#fff" />
              </button>
              {i === 0 && <span className="absolute bottom-1 left-1 px-1.5 py-0.5 rounded-full text-[8px] font-semibold" style={{ background: GOLD, color: BG }}>Cover</span>}
            </div>
          ))}
          {photos.length < MAX_PHOTOS && (
            <button onClick={() => fileInputRef.current?.click()} className="aspect-square rounded-xl flex flex-col items-center justify-center gap-1" style={{ background: CARD, border: `1px dashed ${BORDER}` }}>
              <ImageIcon size={18} color={FAINT} />
              <span className="text-[9px]" style={{ color: FAINT }}>Add photo</span>
            </button>
          )}
        </div>
        <input ref={fileInputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleFilesSelected} />

        <div className="flex flex-col gap-3 mb-4">
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <Tag size={14} color={GOLD} />
            <input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Title (e.g. iPhone 15 Pro, 256GB)" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <DollarSign size={14} color={GOLD} />
            <input value={price} onChange={(e) => setPrice(e.target.value.replace(/[^0-9]/g, ""))} placeholder="Price (SAR)" inputMode="numeric" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          <div className="rounded-xl px-4 py-2" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <select value={category} onChange={(e) => setCategory(e.target.value)} className="bg-transparent outline-none text-sm w-full py-2.5" style={{ color: TEXT }}>
              {CATEGORIES.filter((c) => c !== "All").map((c) => <option key={c} value={c} style={{ background: CARD }}>{c}</option>)}
            </select>
          </div>
          <div className="rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <textarea value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Description (condition, details, etc.)" rows={4} className="bg-transparent outline-none text-sm w-full resize-y" style={{ color: TEXT }} />
          </div>
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <MapPin size={14} color={GOLD} />
            <input value={location} onChange={(e) => setLocation(e.target.value)} placeholder="Location" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
        </div>

        {error && <p className="text-[12px] mb-3" style={{ color: "#C0755B" }}>{error}</p>}
        <button onClick={submit} disabled={uploading} className="w-full mb-6 rounded-full py-3 text-sm font-semibold" style={{ background: uploading ? BORDER : GOLD, color: uploading ? "#5C736D" : BG }}>
          {uploading ? "Posting…" : "Post listing"}
        </button>
      </div>
    </div>
  );
}

/* ---------- STORE REGISTRATION (required, logo mandatory) ---------- */
function StoreRegister({ goBack, navigate, onLoggedIn }) {
  const [storeName, setStoreName] = useState("");
  const [storeType, setStoreType] = useState(STORE_TYPES[0]);
  const [ownerName, setOwnerName] = useState("");
  const [ownerPhone, setOwnerPhone] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [city, setCity] = useState("Riyadh");
  const [hours, setHours] = useState("");
  const [description, setDescription] = useState("");
  const [address, setAddress] = useState("");
  const [coords, setCoords] = useState(SAUDI_CITY_COORDS.Riyadh);
  const [locating, setLocating] = useState(false);
  const [locError, setLocError] = useState("");
  const [logoFile, setLogoFile] = useState(null);
  const [logoPreview, setLogoPreview] = useState(null);
  const logoInputRef = useRef(null);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  async function reverseGeocodeCoords(lat, lng) {
    try {
      const res = await hereFetch(`https://revgeocode.search.hereapi.com/v1/revgeocode?at=${lat},${lng}&lang=en-US`);
      const data = await res.json();
      return data?.items?.[0]?.address?.label || `${lat.toFixed(4)}, ${lng.toFixed(4)}`;
    } catch (e) { return `${lat.toFixed(4)}, ${lng.toFixed(4)}`; }
  }

  async function onStorePinMove(newCoords) {
    setCoords(newCoords);
    const label = await reverseGeocodeCoords(newCoords.lat, newCoords.lng);
    setAddress(label);
  }

  function useMyLocationForStore() {
    detectLocation({
      onStart: () => { setLocating(true); setLocError(""); },
      onSuccess: ({ label, lat, lng }) => { setAddress(label); setCoords({ lat, lng }); setLocating(false); },
      onError: (msg) => { setLocating(false); setLocError(msg); },
    });
  }

  function handleLogoSelected(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setLogoFile(file);
    setLogoPreview(URL.createObjectURL(file));
    e.target.value = "";
  }

  const can = storeName.trim() && ownerName.trim() && ownerPhone.trim() && logoFile && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()) && password.length >= 6;

  async function submit() {
    setError("");
    if (!storeName.trim()) { setError("Please enter your store name."); return; }
    if (!ownerName.trim()) { setError("Please enter your full name."); return; }
    if (!ownerPhone.trim()) { setError("Please enter your mobile number."); return; }
    if (!logoFile) { setError("A store logo is required."); return; }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim())) { setError("Please enter a valid email address — this is how you'll log in to manage your store."); return; }
    if (password.length < 6) { setError("Password must be at least 6 characters."); return; }
    setSaving(true);
    try {
      const authUserId = await signUpOrLinkExisting(email.trim(), password, { role: "store_owner" });

      // If a store already exists with this phone (registered before real
      // login existed), claim it instead of creating a duplicate.
      const { data: claimedId } = await supabase.rpc("claim_legacy_store", { p_phone: ownerPhone.trim() });

      const ext = logoFile.name.split(".").pop() || "jpg";
      const fileName = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
      const { error: logoErr } = await supabase.storage.from("company-logos").upload(fileName, logoFile);
      if (logoErr) throw logoErr;
      const { data: pub } = supabase.storage.from("company-logos").getPublicUrl(fileName);

      if (claimedId) {
        const { error: updErr } = await supabase.from("stores").update({
          owner_name: ownerName.trim(), email: email.trim(), store_name: storeName.trim(), store_type: storeType,
          logo_url: pub.publicUrl, city, hours: hours.trim() || null, address: address.trim() || null,
          lat: coords.lat, lng: coords.lng, description: description.trim() || null, status: "active",
        }).eq("id", claimedId);
        if (updErr) throw updErr;
      } else {
        const { error: insertError } = await supabase.from("stores").insert({
          owner_name: ownerName.trim(),
          owner_phone: ownerPhone.trim(),
          auth_user_id: authUserId,
          email: email.trim(),
          store_name: storeName.trim(),
          store_type: storeType,
          logo_url: pub.publicUrl,
          city,
          hours: hours.trim() || null,
          address: address.trim() || null,
          lat: coords.lat,
          lng: coords.lng,
          description: description.trim() || null,
          status: "active",
        });
        if (insertError) throw insertError;
      }
      const { data: fullProfile } = await supabase.from("stores").select("id, owner_name, owner_phone, store_name, store_type, logo_url, city, hours, description, status, lat, lng, address").eq(claimedId ? "id" : "auth_user_id", claimedId ? claimedId : authUserId).maybeSingle();
      if (onLoggedIn && fullProfile) onLoggedIn({ email: email.trim(), profile: fullProfile });
      navigate("post_marketplace_item");
    } catch (e) {
      setError(e.message || "Couldn't register your store — please try again.");
    } finally {
      setSaving(false);
    }
  }

  return (
    <div style={{ color: TEXT }}>
      <Header title="Register your store" onBack={goBack} />
      <div className="px-5">
        <p className="text-xs mb-2 font-semibold" style={{ color: GREEN }}>STORE LOGO (REQUIRED)</p>
        <div className="flex items-center gap-3 mb-5">
          <button onClick={() => logoInputRef.current?.click()} className="w-20 h-20 rounded-2xl overflow-hidden flex items-center justify-center shrink-0" style={{ background: CARD, border: `1px dashed ${logoPreview ? GOLD : BORDER}` }}>
            {logoPreview ? <img src={logoPreview} alt="Logo" className="w-full h-full object-cover" /> : <ImageIcon size={22} color={FAINT} />}
          </button>
          <div>
            <button onClick={() => logoInputRef.current?.click()} className="text-xs font-semibold" style={{ color: GOLD }}>{logoPreview ? "Change logo" : "Upload logo"}</button>
            <p className="text-[10px] mt-0.5" style={{ color: FAINT }}>Square image works best</p>
          </div>
          <input ref={logoInputRef} type="file" accept="image/*" className="hidden" onChange={handleLogoSelected} />
        </div>

        <div className="flex flex-col gap-3 mb-4">
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <ShoppingBag size={14} color={GOLD} />
            <input value={storeName} onChange={(e) => setStoreName(e.target.value)} placeholder="Store name" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          <div className="rounded-xl px-4 py-2" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <select value={storeType} onChange={(e) => setStoreType(e.target.value)} className="bg-transparent outline-none text-sm w-full py-2.5" style={{ color: TEXT }}>
              {STORE_TYPES.map((t) => <option key={t} value={t} style={{ background: CARD }}>{t}</option>)}
            </select>
          </div>
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <User size={14} color={GOLD} />
            <input value={ownerName} onChange={(e) => setOwnerName(e.target.value)} placeholder="Your full name" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <Phone size={14} color={GOLD} />
            <input value={ownerPhone} onChange={(e) => setOwnerPhone(e.target.value)} placeholder="Mobile number" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${GOLD}` }}>
            <Mail size={14} color={GOLD} />
            <input value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Email — used to log in" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${GOLD}` }}>
            <Key size={14} color={GOLD} />
            <input value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Password (min 6 characters)" type="password" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          <p className="text-[10px] -mt-2" style={{ color: FAINT }}>This becomes your real login — only you, signed in, can ever post to or edit this store.</p>
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <MapPin size={14} color={GOLD} />
            <input value={city} onChange={(e) => setCity(e.target.value)} placeholder="City" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <MapPin size={14} color={GREEN} />
            <input value={address} onChange={(e) => setAddress(e.target.value)} placeholder="Exact address / building" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          <div className="flex items-center justify-between -mt-1">
            <p className="text-[10px]" style={{ color: FAINT }}>Drag the pin to your exact location</p>
            <button onClick={useMyLocationForStore} disabled={locating} className="flex items-center gap-1.5 text-[11px] font-semibold" style={{ color: GOLD }}>
              <Navigation size={12} /> {locating ? "Detecting…" : "Use my current location"}
            </button>
          </div>
          {locError && <p className="text-[11px]" style={{ color: "#C0755B" }}>{locError}</p>}
          <div className="rounded-2xl overflow-hidden" style={{ border: `1px solid ${BORDER}` }}>
            <PinMapPicker coords={coords} onMove={onStorePinMove} height={170} />
          </div>
          <div className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <Clock size={14} color={GOLD} />
            <input value={hours} onChange={(e) => setHours(e.target.value)} placeholder="Opening hours (e.g. 9 AM – 11 PM)" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          <div className="rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <textarea value={description} onChange={(e) => setDescription(e.target.value)} placeholder="About your store (optional)" rows={3} className="bg-transparent outline-none text-sm w-full resize-y" style={{ color: TEXT }} />
          </div>
        </div>

        {error && <p className="text-[12px] mb-3" style={{ color: "#C0755B" }}>{error}</p>}
        <button onClick={submit} disabled={!can || saving} className="w-full mb-6 rounded-full py-3 text-sm font-semibold" style={{ background: can && !saving ? GOLD : BORDER, color: can && !saving ? BG : "#5C736D" }}>
          {saving ? "Registering…" : "Register store"}
        </button>
      </div>
    </div>
  );
}

