function EditActivityItemModal({ item, onClose, onSaved }) {
  const cfg = EDIT_TABLE_CONFIG[item.table] || EDIT_TABLE_CONFIG.marketplace_listings;
  const [name, setName] = useState(item.raw[cfg.nameField] || "");
  const [price, setPrice] = useState(cfg.hasPrice && item.raw[cfg.priceField] != null ? String(item.raw[cfg.priceField]) : "");
  const [description, setDescription] = useState(item.raw.description || "");
  const [status, setStatus] = useState(item.raw.status || "active");
  const [saving, setSaving] = useState(false);

  async function save() {
    setSaving(true);
    const payload = { [cfg.nameField]: name.trim(), status };
    if (cfg.hasPrice) payload[cfg.priceField] = price ? Number(price) : null;
    if (cfg.hasDescription) payload.description = description.trim() || null;
    const { error } = await supabase.from(item.table).update(payload).eq("id", item.id);
    setSaving(false);
    if (!error) onSaved();
    else alert("Couldn't save changes — please try again.");
  }

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center" style={{ background: "rgba(0,0,0,0.6)" }} onClick={onClose}>
      <div className="w-full max-w-md rounded-t-3xl p-5" style={{ background: CARD, border: `1px solid ${BORDER}` }} onClick={(e) => e.stopPropagation()}>
        <p className="text-sm font-semibold mb-4">Edit {cfg.label}</p>
        <div className="flex flex-col gap-3 mb-4">
          <div className="rounded-xl px-4 py-3" style={{ background: BG, border: `1px solid ${BORDER}` }}>
            <input value={name} onChange={(e) => setName(e.target.value)} placeholder={cfg.nameLabel} className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
          </div>
          {cfg.hasPrice && (
            <div className="rounded-xl px-4 py-3" style={{ background: BG, border: `1px solid ${BORDER}` }}>
              <input value={price} onChange={(e) => setPrice(e.target.value.replace(/[^0-9]/g, ""))} placeholder={cfg.priceLabel || "Price (SAR)"} inputMode="numeric" className="bg-transparent outline-none text-sm w-full" style={{ color: TEXT }} />
            </div>
          )}
          {cfg.hasDescription && (
            <div className="rounded-xl px-4 py-3" style={{ background: BG, border: `1px solid ${BORDER}` }}>
              <textarea value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Description" rows={3} className="bg-transparent outline-none text-sm w-full resize-y" style={{ color: TEXT }} />
            </div>
          )}
          <div className="rounded-xl px-4 py-2" style={{ background: BG, border: `1px solid ${BORDER}` }}>
            <select value={status} onChange={(e) => setStatus(e.target.value)} className="bg-transparent outline-none text-sm w-full py-2.5" style={{ color: TEXT }}>
              <option value="active" style={{ background: CARD }}>Active</option>
              <option value="hidden" style={{ background: CARD }}>Hidden</option>
            </select>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={onClose} className="flex-1 rounded-full py-3 text-sm font-semibold" style={{ background: BORDER, color: TEXT }}>Cancel</button>
          <button onClick={save} disabled={saving} className="flex-1 rounded-full py-3 text-sm font-semibold" style={{ background: GOLD, color: BG }}>{saving ? "Saving…" : "Save changes"}</button>
        </div>
      </div>
    </div>
  );
}

function TripHistory({ goBack }) {
  const [trips, setTrips] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function load() {
      let refs = [];
      try { refs = JSON.parse(localStorage.getItem("sayyara_my_rides") || "[]"); } catch (e) {}
      if (refs.length === 0) { setLoading(false); return; }
      const { data } = await supabase.from("rides").select("*").in("booking_ref", refs).order("created_at", { ascending: false });
      setTrips(data || []);
      setLoading(false);
    }
    load();
  }, []);

  return (
    <div style={{ color: TEXT }}>
      <Header title="Activity" onBack={goBack} />
      <div className="px-5 mb-4">
        <div className="rounded-2xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
          <p className="text-xs" style={{ color: FAINT }}>Total trips</p>
          <p className="text-lg font-semibold">{trips.length}</p>
        </div>
      </div>
      {loading && <div className="px-5 flex flex-col gap-2">{[1, 2, 3].map((i) => <SkeletonRow key={i} />)}</div>}
      {!loading && trips.length === 0 && (
        <EmptyState icon={Route} title="No trips yet" subtitle="Rides you book on this device will show up here." />
      )}
      <div className="px-5 grid grid-cols-1 lg:grid-cols-2 gap-2">
        {!loading && trips.map((t) => {
          const meta = TYPE_META[t.ride_type] || TYPE_META.ride;
          const Icon = meta.icon;
          const statusColor = t.status === "completed" ? GREEN : t.status === "cancelled" ? "#C0755B" : GOLD;
          return (
            <div key={t.id} className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
              <div className="w-10 h-10 rounded-lg flex items-center justify-center shrink-0" style={{ background: "rgba(217,166,83,0.12)" }}><Icon size={17} color={GOLD} /></div>
              <div className="flex-1">
                <div className="flex items-center justify-between">
                  <p className="text-sm font-semibold">{meta.label}</p>
                  <span className="px-2 py-0.5 rounded-full text-[9px] font-semibold" style={{ background: `${statusColor}22`, color: statusColor }}>{t.status}</span>
                </div>
                <p className="text-[11px] mt-0.5" style={{ color: FAINT }}>{t.pickup_label} → {t.dropoff_label}</p>
                {t.distance_km && <p className="text-[10px] mt-0.5" style={{ color: FAINT }}>{t.distance_km} km · ~{t.duration_min} min</p>}
                <p className="text-[10px] mt-1" style={{ color: FAINT }}>{new Date(t.created_at).toLocaleDateString()}</p>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ---------- DRIVER TRIP HISTORY ---------- */

function DriverTripHistory({ goBack, currentDriver }) {
  const [trips, setTrips] = useState([]);
  const [loading, setLoading] = useState(true);
  const driverId = currentDriver?.profile?.id;

  useEffect(() => {
    async function load() {
      if (!driverId) { setLoading(false); return; }
      const { data } = await supabase.from("rides").select("*").eq("driver_id", driverId).eq("status", "completed").order("created_at", { ascending: false });
      setTrips(data || []);
      setLoading(false);
    }
    load();
  }, [driverId]);

  const totalDistance = trips.reduce((s, t) => s + (t.distance_km || 0), 0);

  return (
    <div style={{ color: TEXT }}>
      <Header title="Trip history" onBack={goBack} />
      <div className="px-5 mb-4">
        <div className="rounded-2xl px-4 py-3 flex items-center justify-between" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
          <div><p className="text-xs" style={{ color: FAINT }}>Total distance</p><p className="text-lg font-semibold" style={{ color: GOLD }}>{totalDistance.toFixed(1)} km</p></div>
          <div className="text-right"><p className="text-xs" style={{ color: FAINT }}>Trips completed</p><p className="text-lg font-semibold">{trips.length}</p></div>
        </div>
      </div>
      {loading && <div className="px-5 flex flex-col gap-2">{[1, 2, 3].map((i) => <SkeletonRow key={i} />)}</div>}
      {!loading && !driverId && (
        <EmptyState icon={Route} title="Log in to see your trips" subtitle="Your real trip history will appear here once you're logged in." />
      )}
      {!loading && driverId && trips.length === 0 && (
        <EmptyState icon={Route} title="No completed trips yet" subtitle="Trips you complete will show up here." />
      )}
      <div className="px-5 grid grid-cols-1 lg:grid-cols-2 gap-2">
        {!loading && trips.map((t) => {
          const meta = TYPE_META[t.ride_type] || TYPE_META.ride;
          const Icon = meta.icon;
          return (
            <div key={t.id} className="flex items-center gap-3 rounded-xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
              <div className="w-10 h-10 rounded-lg flex items-center justify-center shrink-0" style={{ background: "rgba(217,166,83,0.12)" }}><Icon size={17} color={GOLD} /></div>
              <div className="flex-1">
                <div className="flex items-center justify-between">
                  <p className="text-sm font-semibold">{meta.label}</p>
                  {t.distance_km && <p className="text-[11px] font-semibold" style={{ color: GREEN }}>{t.distance_km} km</p>}
                </div>
                <p className="text-[11px] mt-0.5" style={{ color: FAINT }}>{t.pickup_label} → {t.dropoff_label}</p>
                <p className="text-[10px] mt-1" style={{ color: FAINT }}>{new Date(t.created_at).toLocaleDateString()}</p>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
/* ---------- WALLET (placeholder tab) ---------- */
function WalletTab({ goBack, currentDriver, navigate }) {
  const isDriver = currentDriver?.type === "driver";
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ total: 0, week: 0, month: 0, trips: 0 });

  useEffect(() => {
    async function loadDriverEarnings() {
      const startOfWeek = new Date(); startOfWeek.setDate(startOfWeek.getDate() - startOfWeek.getDay()); startOfWeek.setHours(0, 0, 0, 0);
      const startOfMonth = new Date(); startOfMonth.setDate(1); startOfMonth.setHours(0, 0, 0, 0);
      const { data } = await supabase.from("rides").select("fare_estimate, created_at").eq("driver_id", currentDriver.profile.id).eq("status", "completed");
      const rows = data || [];
      const total = rows.reduce((s, r) => s + (r.fare_estimate || 0), 0);
      const week = rows.filter((r) => new Date(r.created_at) >= startOfWeek).reduce((s, r) => s + (r.fare_estimate || 0), 0);
      const month = rows.filter((r) => new Date(r.created_at) >= startOfMonth).reduce((s, r) => s + (r.fare_estimate || 0), 0);
      setStats({ total, week, month, trips: rows.length });
      setLoading(false);
    }
    async function loadPassengerSpend() {
      let refs = [];
      try { refs = JSON.parse(localStorage.getItem("sayyara_my_rides") || "[]"); } catch (e) {}
      if (refs.length === 0) { setLoading(false); return; }
      const { data } = await supabase.from("rides").select("fare_estimate, status").in("booking_ref", refs).eq("status", "completed");
      const rows = data || [];
      setStats({ total: rows.reduce((s, r) => s + (r.fare_estimate || 0), 0), week: 0, month: 0, trips: rows.length });
      setLoading(false);
    }
    if (isDriver && currentDriver?.profile?.id) loadDriverEarnings();
    else if (!isDriver) loadPassengerSpend();
    else setLoading(false);
  }, [isDriver, currentDriver?.profile?.id]);

  return (
    <div style={{ color: TEXT }}>
      <Header title="Wallet" onBack={goBack} />
      <div className="px-5 mb-4">
        <div className="rounded-2xl px-4 py-5 text-center" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
          <p className="text-xs" style={{ color: FAINT }}>{isDriver ? "Total earnings (all time)" : "Total spent (all time)"}</p>
          <p className="text-3xl font-bold mt-1" style={{ color: GOLD }}>{loading ? "…" : stats.total.toFixed(0)} <span className="text-sm font-normal" style={{ color: FAINT }}>SAR</span></p>
          <p className="text-xs mt-2" style={{ color: MUTE }}>Cash payments only for now — no wallet top-up needed.</p>
        </div>
      </div>
      {isDriver && (
        <div className="px-5 mb-4 grid grid-cols-2 gap-2">
          <div className="rounded-2xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <p className="text-[11px]" style={{ color: FAINT }}>This week</p>
            <p className="text-lg font-semibold mt-0.5">{loading ? "…" : stats.week.toFixed(0)} SAR</p>
          </div>
          <div className="rounded-2xl px-4 py-3" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
            <p className="text-[11px]" style={{ color: FAINT }}>This month</p>
            <p className="text-lg font-semibold mt-0.5">{loading ? "…" : stats.month.toFixed(0)} SAR</p>
          </div>
        </div>
      )}
      <div className="px-5 mb-4">
        <div className="rounded-2xl px-4 py-3 flex items-center justify-between" style={{ background: CARD, border: `1px solid ${BORDER}` }}>
          <p className="text-xs" style={{ color: FAINT }}>Completed trips</p>
          <p className="text-sm font-semibold">{loading ? "…" : stats.trips}</p>
        </div>
      </div>
      <div className="px-5">
        <button onClick={() => navigate(isDriver ? "driver_trips" : "activity")} className="w-full flex items-center justify-center gap-2 rounded-full py-3 text-sm font-semibold" style={{ background: CARD, border: `1px solid ${BORDER}`, color: TEXT }}>
          <Route size={15} /> View full trip history
        </button>
      </div>
    </div>
  );
}
